# ticket_router.py
# Auto-classify new tickets and suggest tier assignment

from dataclasses import dataclass
from enum import Enum
import re

class Tier(str, Enum):
    L1 = "L1"
    L2 = "L2"
    L3 = "L3"
    INCIDENT = "INCIDENT"  # SEV1/2 bypass straight to incident management

L1_KEYWORDS = [
    "how to", "documentation", "getting started",
    "billing", "password", "login", "api key", "quota",
    "rate limit", "timeout", "slow response"
]

L2_KEYWORDS = [
    "wrong answer", "incorrect output", "unexpected behavior",
    "agent loop", "tool call", "context window", "prompt",
    "guardrail", "refused", "hallucination", "stuck", "not following instructions"
]

L3_KEYWORDS = [
    "data loss", "security", "breach", "all customers", "widespread",
    "500 error", "service down", "cannot access", "outage"
]

SEV_PATTERNS = [
    r"urgent", r"critical", r"sev[ -]?[12]", r"production down",
    r"blocking all", r"data exposure"
]

@dataclass
class Ticket:
    id: str
    title: str
    description: str
    customer_tier: str  # enterprise, managed, self-serve
    submitted_via: str  # email, slack, portal, api

def classify(ticket: Ticket) -> tuple[Tier, str]:
    text = (ticket.title + " " + ticket.description).lower()

    # SEV override: goes straight to incident process
    for pattern in SEV_PATTERNS:
        if re.search(pattern, text):
            return Tier.INCIDENT, f"SEV pattern matched: '{pattern}'"

    # Enterprise customers with L2/L3 keywords skip L1
    if ticket.customer_tier == "enterprise":
        for kw in L3_KEYWORDS:
            if kw in text:
                return Tier.L3, f"Enterprise + L3 keyword: '{kw}'"
        for kw in L2_KEYWORDS:
            if kw in text:
                return Tier.L2, f"Enterprise + L2 keyword: '{kw}'"

    # Standard routing
    for kw in L3_KEYWORDS:
        if kw in text:
            return Tier.L2, f"L3 keyword suggested L2 initial: '{kw}'"  # L2 assesses before L3
    for kw in L2_KEYWORDS:
        if kw in text:
            return Tier.L2, f"L2 keyword: '{kw}'"
    for kw in L1_KEYWORDS:
        if kw in text:
            return Tier.L1, f"L1 keyword: '{kw}'"

    return Tier.L1, "No strong signal — default L1"

# Example
if __name__ == "__main__":
    tickets = [
        Ticket("T-001", "Agent giving wrong answer", "The agent keeps saying the product is discontinued but it isn't", "managed", "email"),
        Ticket("T-002", "How do I set rate limits", "Need to throttle requests per user", "self-serve", "portal"),
        Ticket("T-003", "Production down all customers cannot access", "API returning 500 for all requests", "enterprise", "slack"),
    ]
    for t in tickets:
        tier, reason = classify(t)
        print(f"[{t.id}] -> {tier.value}: {reason}")
